SELECT AddressView.address_state, SUM(OrderItemView.orderItem_quantity) FROM AddressView, CustomerView, OrderView, OrderItemView WHERE AddressView.address_customerId = CustomerView.customer_id AND OrderView.order_customerId = CustomerView.customer_id AND OrderItemView.orderItem_orderId = OrderView.order_id GROUP BY AddressView.address_state ORDER BY AddressView.address_state;
SELECT AddressView.address_state, TaxRecordView.taxRecord_bracket, COUNT(TaxRecordView.taxRecord_id) FROM AddressView, TaxRecordView WHERE TaxRecordView.taxRecord_addressId = AddressView.address_id AND TaxRecordView.taxRecord_value > 149670.0 GROUP BY AddressView.address_state, TaxRecordView.taxRecord_bracket ORDER BY AddressView.address_state, TaxRecordView.taxRecord_bracket;
SELECT CustomerView.customer_priority, TaxRecordView.taxRecord_bracket, AVG(OrderItemView.orderItem_weight) FROM OrderItemView, OrderView, ProductView, CreditCardView, CustomerView, AddressView, TaxRecordView WHERE OrderItemView.orderItem_orderId = OrderView.order_id AND OrderItemView.orderItem_productId = ProductView.product_id AND OrderView.order_creditCardNumber = CreditCardView.creditCard_number AND OrderView.order_customerId = CustomerView.customer_id AND AddressView.address_customerId = CustomerView.customer_id AND TaxRecordView.taxRecord_addressId = AddressView.address_id AND CreditCardView.creditCard_lastChargeAmount > 90.0 AND ProductView.product_price > 34.0 GROUP BY CustomerView.customer_priority, TaxRecordView.taxRecord_bracket ORDER BY CustomerView.customer_priority, TaxRecordView.taxRecord_bracket;
SELECT OrderView.order_serverId, COUNT(ProductView.product_id) FROM CategoryView, ProductView, OrderItemView, OrderView WHERE ProductView.product_categoryName = CategoryView.category_name AND OrderItemView.orderItem_productId = ProductView.product_id AND OrderItemView.orderItem_orderId = OrderView.order_id AND OrderItemView.orderItem_weight > 15.0 GROUP BY OrderView.order_serverId ORDER BY OrderView.order_serverId;
SELECT TaxRecordView.taxRecord_bracket, SUM(OrderItemView.orderItem_quantity) FROM TaxRecordView, AddressView, CustomerView, OrderView, OrderItemView, ProductView WHERE TaxRecordView.taxRecord_addressId = AddressView.address_id AND AddressView.address_customerId = CustomerView.customer_id AND OrderView.order_customerId = CustomerView.customer_id AND OrderItemView.orderItem_orderId = OrderView.order_id AND OrderItemView.orderItem_productId = ProductView.product_id AND OrderView.order_placedOn > 1579003950 GROUP BY TaxRecordView.taxRecord_bracket ORDER BY TaxRecordView.taxRecord_bracket;
SELECT AddressView.address_state, AVG(AddressView.address_zone) FROM CategoryView, ProductView, OrderItemView, OrderView, CustomerView, AddressView WHERE ProductView.product_categoryName = CategoryView.category_name AND OrderItemView.orderItem_productId = ProductView.product_id AND OrderItemView.orderItem_orderId = OrderView.order_id AND OrderView.order_customerId = CustomerView.customer_id AND AddressView.address_customerId = CustomerView.customer_id AND AddressView.address_state IN ('PA', 'CA', 'VA', 'MA', 'ME', 'MD', 'CO', 'MO') AND CategoryView.category_seasonal = 1 GROUP BY AddressView.address_state ORDER BY AddressView.address_state;
SELECT CustomerView.customer_age, CustomerView.customer_balance, COUNT(CustomerView.customer_id) FROM CustomerView, AddressView, TaxRecordView WHERE AddressView.address_customerId = CustomerView.customer_id AND TaxRecordView.taxRecord_addressId = AddressView.address_id AND TaxRecordView.taxRecord_bracketThreshold = 24 GROUP BY CustomerView.customer_age, CustomerView.customer_balance ORDER BY CustomerView.customer_age, CustomerView.customer_balance;
SELECT OrderView.order_serverId, SUM(CreditCardView.creditCard_lastChargeAmount) FROM CreditCardView, OrderView, OrderItemView, ProductView, CategoryView WHERE OrderView.order_creditCardNumber = CreditCardView.creditCard_number AND OrderItemView.orderItem_orderId = OrderView.order_id AND OrderItemView.orderItem_productId = ProductView.product_id AND ProductView.product_categoryName = CategoryView.category_name AND OrderItemView.orderItem_weight < 25.0 AND ProductView.product_price < 200.0 GROUP BY OrderView.order_serverId ORDER BY OrderView.order_serverId;
